import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinTree;
import org.junit.jupiter.api.Test;

class CascadesPartitionJoinEnumerationTest {

	private static final String PREDICATE_PREFIX = "partitionPredicate";
	private static final int EIGHT_FACTOR_PARTITION_BOUND = 6_050;

	@Test
	void disconnectedEightFactorRegionUsesPartitionScaleMemoEnumeration() {
		Set<String> uniqueMemoExpressions = new HashSet<>();
		ExhaustiveLegalJoinSearchContributor delegate = new ExhaustiveLegalJoinSearchContributor();
		JoinSearchContributor cappedExhaustive = new JoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor("partition-scale-exhaustive",
					Coverage.EXHAUSTIVE_LEGAL,
					1_000);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				return delegate.contribute(request, sink);
			}

			@Override
			public Outcome contributeMemoExpressions(JoinSearchRequest request, MemoExpressionSink sink) {
				return delegate.contributeMemoExpressions(request, expression -> {
					if (uniqueMemoExpressions.add(expression.canonicalForm())
							&& uniqueMemoExpressions.size() > EIGHT_FACTOR_PARTITION_BOUND) {
						throw new AssertionError("Exhaustive memo enumeration expanded more than "
								+ EIGHT_FACTOR_PARTITION_BOUND
								+ " unique subset partitions; it is retaining complete join trees instead");
					}
					sink.accept(expression);
				});
			}
		};
		CascadesPlan plan = planner(new JoinSearchService(List.of(cappedExhaustive)))
				.optimize(disconnectedJoin(8), OptimizationGoal.root());

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
		assertTrue(uniqueMemoExpressions.size() <= EIGHT_FACTOR_PARTITION_BOUND,
				"Eight factors need at most 3^8 - 2*2^8 + 1 oriented subset partitions");
		Set<MemoPartition> expected = allOrientedPartitions(8);
		assertEquals(EIGHT_FACTOR_PARTITION_BOUND, expected.size());
		assertTrue(memoPartitions(plan.memo()).containsAll(expected),
				"The memo must retain every legal subset partition without expanding every complete tree");
	}

	@Test
	void subsetPartitionsRepresentIndependentBruteForceWinners() {
		for (int factorCount = 2; factorCount <= 5; factorCount++) {
			CascadesPlan plan = planner(new JoinSearchService(List.of(new ExhaustiveLegalJoinSearchContributor())))
					.optimize(disconnectedJoin(factorCount), OptimizationGoal.root());
			JoinTree oracleWinner = bruteForceWinner(factorCount);
			Set<MemoPartition> requiredPartitions = treePartitions(oracleWinner);

			assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), "factorCount=" + factorCount);
			assertTrue(memoPartitions(plan.memo()).containsAll(requiredPartitions),
					"Memo alternatives cannot compose independent oracle winner "
							+ oracleWinner.canonicalForm() + " for factorCount=" + factorCount);
		}
	}

	private static CascadesPlanner planner(JoinSearchService joinSearchService) {
		return new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.standardLogicalRules(), CascadesTelemetry.NO_OP, 16, RewriteMetadata.empty(),
				joinSearchService);
	}

	private static TupleExpr disconnectedJoin(int factorCount) {
		TupleExpr result = pattern(0);
		for (int occurrenceId = 1; occurrenceId < factorCount; occurrenceId++) {
			result = new Join(result, pattern(occurrenceId));
		}
		return result;
	}

	private static StatementPattern pattern(int occurrenceId) {
		return new StatementPattern(new Var("subject" + occurrenceId),
				new Var(PREDICATE_PREFIX + occurrenceId), new Var("object" + occurrenceId));
	}

	private static Set<MemoPartition> memoPartitions(Memo memo) {
		Map<Integer, Set<Integer>> occurrencesByGroup = occurrenceSetsByGroup(memo);
		Set<MemoPartition> result = new HashSet<>();
		for (MemoGroup group : memo.groups()) {
			for (MemoExpr expression : group.expressions()) {
				if (!expression.logical() || !(expression.tupleExpr() instanceof Join)
						|| expression.inputGroupIds().size() != 2) {
					continue;
				}
				Set<Integer> left = occurrencesByGroup.get(expression.inputGroupIds().get(0));
				Set<Integer> right = occurrencesByGroup.get(expression.inputGroupIds().get(1));
				if (left != null && right != null) {
					result.add(new MemoPartition(union(left, right), left, right));
				}
			}
		}
		return Set.copyOf(result);
	}

	private static Map<Integer, Set<Integer>> occurrenceSetsByGroup(Memo memo) {
		Map<Integer, Set<Integer>> result = new HashMap<>();
		for (MemoGroup group : memo.groups()) {
			for (MemoExpr expression : group.expressions()) {
				if (expression.logical() && expression.tupleExpr()instanceof StatementPattern pattern) {
					String predicateName = pattern.getPredicateVar().getName();
					if (predicateName.startsWith(PREDICATE_PREFIX)) {
						result.put(group.id(),
								Set.of(Integer.parseInt(predicateName.substring(PREDICATE_PREFIX.length()))));
					}
				}
			}
		}
		boolean changed;
		do {
			changed = false;
			for (MemoGroup group : memo.groups()) {
				for (MemoExpr expression : group.expressions()) {
					if (!expression.logical() || !(expression.tupleExpr() instanceof Join)
							|| expression.inputGroupIds().size() != 2) {
						continue;
					}
					Set<Integer> left = result.get(expression.inputGroupIds().get(0));
					Set<Integer> right = result.get(expression.inputGroupIds().get(1));
					if (left != null && right != null && !result.containsKey(group.id())) {
						result.put(group.id(), union(left, right));
						changed = true;
					}
				}
			}
		} while (changed);
		return result;
	}

	private static Set<MemoPartition> allOrientedPartitions(int factorCount) {
		Set<MemoPartition> result = new HashSet<>();
		int limit = 1 << factorCount;
		for (int wholeMask = 1; wholeMask < limit; wholeMask++) {
			if (Integer.bitCount(wholeMask) < 2) {
				continue;
			}
			for (int leftMask = (wholeMask - 1) & wholeMask; leftMask > 0; leftMask = (leftMask - 1) & wholeMask) {
				int rightMask = wholeMask ^ leftMask;
				result.add(new MemoPartition(occurrences(wholeMask), occurrences(leftMask), occurrences(rightMask)));
			}
		}
		return Set.copyOf(result);
	}

	private static JoinTree bruteForceWinner(int factorCount) {
		Set<Integer> factorIds = new LinkedHashSet<>();
		for (int occurrenceId = 0; occurrenceId < factorCount; occurrenceId++) {
			factorIds.add(occurrenceId);
		}
		return enumerateTrees(factorIds, new HashMap<>()).stream()
				.min(Comparator.comparing(CascadesPartitionJoinEnumerationTest::oracleCost)
						.thenComparing(JoinTree::canonicalForm))
				.orElseThrow();
	}

	private static List<JoinTree> enumerateTrees(Set<Integer> factorIds, Map<Set<Integer>, List<JoinTree>> cache) {
		Set<Integer> key = Set.copyOf(factorIds);
		List<JoinTree> cached = cache.get(key);
		if (cached != null) {
			return cached;
		}
		if (factorIds.size() == 1) {
			List<JoinTree> singleton = List.of(JoinTree.factor(factorIds.iterator().next()));
			cache.put(key, singleton);
			return singleton;
		}
		List<Integer> ordered = factorIds.stream().sorted().toList();
		LinkedHashSet<JoinTree> trees = new LinkedHashSet<>();
		int partitionCount = 1 << ordered.size();
		for (int mask = 1; mask < partitionCount - 1; mask++) {
			Set<Integer> leftIds = new HashSet<>();
			Set<Integer> rightIds = new HashSet<>();
			for (int index = 0; index < ordered.size(); index++) {
				(maskContains(mask, index) ? leftIds : rightIds).add(ordered.get(index));
			}
			for (JoinTree left : enumerateTrees(leftIds, cache)) {
				for (JoinTree right : enumerateTrees(rightIds, cache)) {
					trees.add(JoinTree.join(left, right));
				}
			}
		}
		List<JoinTree> result = List.copyOf(trees);
		cache.put(key, result);
		return result;
	}

	private static OracleCost oracleCost(JoinTree tree) {
		if (tree instanceof JoinTree.Factor factor) {
			double rows = 2.0 + factor.occurrenceId() * factor.occurrenceId();
			return new OracleCost(rows, rows, 1);
		}
		JoinTree.Join join = (JoinTree.Join) tree;
		OracleCost left = oracleCost(join.left());
		OracleCost right = oracleCost(join.right());
		double outputRows = Math.max(1.0, left.outputRows() * right.outputRows()
				/ (2.0 + left.factorCount() + 2.0 * right.factorCount()));
		double localWork = left.outputRows() + 3.0 * right.outputRows()
				+ left.outputRows() * right.outputRows();
		return new OracleCost(outputRows, left.totalWork() + right.totalWork() + localWork,
				left.factorCount() + right.factorCount());
	}

	private static Set<MemoPartition> treePartitions(JoinTree tree) {
		Set<MemoPartition> result = new HashSet<>();
		collectTreePartitions(tree, result);
		return Set.copyOf(result);
	}

	private static Set<Integer> collectTreePartitions(JoinTree tree, Set<MemoPartition> result) {
		if (tree instanceof JoinTree.Factor factor) {
			return Set.of(factor.occurrenceId());
		}
		JoinTree.Join join = (JoinTree.Join) tree;
		Set<Integer> left = collectTreePartitions(join.left(), result);
		Set<Integer> right = collectTreePartitions(join.right(), result);
		Set<Integer> whole = union(left, right);
		result.add(new MemoPartition(whole, left, right));
		return whole;
	}

	private static Set<Integer> occurrences(int mask) {
		Set<Integer> result = new HashSet<>();
		for (int bit = 0; bit < Integer.SIZE; bit++) {
			if ((mask & (1 << bit)) != 0) {
				result.add(bit);
			}
		}
		return Set.copyOf(result);
	}

	private static Set<Integer> union(Set<Integer> left, Set<Integer> right) {
		Set<Integer> result = new HashSet<>(left);
		result.addAll(right);
		return Set.copyOf(result);
	}

	private static boolean maskContains(int mask, int index) {
		return (mask & (1 << index)) != 0;
	}

	private record MemoPartition(Set<Integer> whole, Set<Integer> left, Set<Integer> right) {
		private MemoPartition {
			whole = Set.copyOf(whole);
			left = Set.copyOf(left);
			right = Set.copyOf(right);
		}
	}

	private record OracleCost(double outputRows, double totalWork, int factorCount)
			implements Comparable<OracleCost> {

		@Override
		public int compareTo(OracleCost other) {
			int totalComparison = Double.compare(totalWork, other.totalWork);
			return totalComparison != 0 ? totalComparison : Double.compare(outputRows, other.outputRows);
		}
	}
}
